local cjson = require "cjson"

-- Simple SAX-like XML parser that prevents XXE attacks
-- Does NOT resolve external entities, DOCTYPE declarations, or parameter entities

local XMLParser = {}
XMLParser.__index = XMLParser

function XMLParser.new()
    local self = setmetatable({}, XMLParser)
    self.predefined_entities = {
        amp = "&",
        lt = "<",
        gt = ">",
        apos = "'",
        quot = '"'
    }
    return self
end

-- Check for XXE attack vectors in raw XML
function XMLParser:check_xxe_threats(xml_str)
    -- Block DOCTYPE declarations entirely (prevents all XXE variants)
    if xml_str:match("<!DOCTYPE") or xml_str:match("<!doctype") then
        return false, "DOCTYPE declarations are not allowed (XXE prevention)"
    end

    -- Block ENTITY declarations
    if xml_str:match("<!ENTITY") or xml_str:match("<!entity") then
        return false, "ENTITY declarations are not allowed (XXE prevention)"
    end

    -- Block SYSTEM and PUBLIC identifiers
    if xml_str:match("SYSTEM%s") or xml_str:match("PUBLIC%s") then
        return false, "SYSTEM/PUBLIC identifiers are not allowed (XXE prevention)"
    end

    -- Block XInclude
    if xml_str:match("xmlns:xi%s*=") or xml_str:match("xi:include") then
        return false, "XInclude is not allowed (XXE prevention)"
    end

    -- Block processing instructions that could be dangerous
    if xml_str:match("<%?xml%-stylesheet") then
        return false, "xml-stylesheet processing instructions are not allowed"
    end

    return true, nil
end

-- Resolve only predefined XML entities (safe ones)
function XMLParser:resolve_entity(entity_ref)
    local entity_name = entity_ref:match("^&(.-);$")
    if not entity_name then
        return nil, "Invalid entity reference: " .. tostring(entity_ref)
    end

    -- Allow numeric character references
    if entity_name:sub(1, 1) == "#" then
        local code
        if entity_name:sub(2, 2) == "x" or entity_name:sub(2, 2) == "X" then
            code = tonumber(entity_name:sub(3), 16)
        else
            code = tonumber(entity_name:sub(2))
        end
        if code and code > 0 and code <= 0x10FFFF then
            -- Convert Unicode code point to UTF-8
            if code < 0x80 then
                return string.char(code)
            elseif code < 0x800 then
                return string.char(
                    0xC0 + math.floor(code / 0x40),
                    0x80 + (code % 0x40)
                )
            elseif code < 0x10000 then
                return string.char(
                    0xE0 + math.floor(code / 0x1000),
                    0x80 + math.floor((code % 0x1000) / 0x40),
                    0x80 + (code % 0x40)
                )
            else
                return string.char(
                    0xF0 + math.floor(code / 0x40000),
                    0x80 + math.floor((code % 0x40000) / 0x1000),
                    0x80 + math.floor((code % 0x1000) / 0x40),
                    0x80 + (code % 0x40)
                )
            end
        end
        return nil, "Invalid numeric character reference: " .. entity_ref
    end

    -- Only allow predefined XML entities
    local resolved = self.predefined_entities[entity_name]
    if resolved then
        return resolved
    end

    return nil, "Unknown entity reference not allowed (XXE prevention): &" .. entity_name .. ";"
end

-- Replace all entity references in text with safe resolved values
function XMLParser:resolve_entities_in_text(text)
    local result = text
    local err
    result = result:gsub("(&.-;)", function(entity_ref)
        local resolved, resolve_err = self:resolve_entity(entity_ref)
        if not resolved then
            err = resolve_err
            return entity_ref
        end
        return resolved
    end)
    if err then
        return nil, err
    end
    return result
end

-- Trim whitespace
local function trim(s)
    return s:match("^%s*(.-)%s*$")
end

-- Parse attributes from a tag string
function XMLParser:parse_attributes(attr_str)
    local attrs = {}
    for name, value in attr_str:gmatch('([%w_:%-%.]+)%s*=%s*"(.-)"') do
        local resolved, err = self:resolve_entities_in_text(value)
        if not resolved then
            return nil, err
        end
        attrs[name] = resolved
    end
    -- Also handle single-quoted attributes
    for name, value in attr_str:gmatch("([%w_:%-%.]+)%s*=%s*'(.-)'") do
        if not attrs[name] then
            local resolved, err = self:resolve_entities_in_text(value)
            if not resolved then
                return nil, err
            end
            attrs[name] = resolved
        end
    end
    return attrs
end

-- Main parse function: returns a Lua table representation of the XML
function XMLParser:parse(xml_str)
    if not xml_str or xml_str == "" then
        return nil, "Empty XML input"
    end

    -- First, check for XXE threats
    local safe, threat_err = self:check_xxe_threats(xml_str)
    if not safe then
        return nil, threat_err
    end

    -- Remove XML declaration
    xml_str = xml_str:gsub("<%?xml.-<%?>", "")

    -- Remove comments
    xml_str = xml_str:gsub("<!%-%-.-%--%>", "")

    -- Remove CDATA sections by extracting their content
    xml_str = xml_str:gsub("<!%[CDATA%[(.-)%]%]>", function(content)
        -- Escape special XML chars in CDATA content so they survive as text
        content = content:gsub("&", "&amp;")
        content = content:gsub("<", "&lt;")
        content = content:gsub(">", "&gt;")
        return content
    end)

    local stack = {}
    local root = { _children = {}, _type = "root" }
    local current = root

    table.insert(stack, current)

    local pos = 1
    local len = #xml_str

    while pos <= len do
        local tag_start = xml_str:find("<", pos)

        if not tag_start then
            -- Remaining text
            local text = xml_str:sub(pos)
            text = trim(text)
            if text ~= "" then
                local resolved, err = self:resolve_entities_in_text(text)
                if not resolved then
                    return nil, err
                end
                if current._text then
                    current._text = current._text .. resolved
                else
                    current._text = resolved
                end
            end
            break
        end

        -- Text before the tag
        if tag_start > pos then
            local text = xml_str:sub(pos, tag_start - 1)
            text = trim(text)
            if text ~= "" then
                local resolved, err = self:resolve_entities_in_text(text)
                if not resolved then
                    return nil, err
                end
                if current._text then
                    current._text = current._text .. resolved
                else
                    current._text = resolved
                end
            end
        end

        local tag_end = xml_str:find(">", tag_start)
        if not tag_end then
            return nil, "Malformed XML: unclosed tag at position " .. tag_start
        end

        local tag_content = xml_str:sub(tag_start + 1, tag_end - 1)

        if tag_content:sub(1, 1) == "/" then
            -- Closing tag
            local tag_name = trim(tag_content:sub(2))
            if current._name ~= tag_name then
                return nil, "Mismatched closing tag: expected </" ..
                    tostring(current._name) .. "> but found </" .. tag_name .. ">"
            end
            table.remove(stack)
            current = stack[#stack]
            if not current then
                return nil, "Malformed XML: extra closing tag </" .. tag_name .. ">"
            end
        elseif tag_content:sub(-1) == "/" then
            -- Self-closing tag
            local inner = trim(tag_content:sub(1, -2))
            local tag_name = inner:match("^([%w_:%-%.]+)")
            if not tag_name then
                return nil, "Malformed XML: invalid self-closing tag"
            end
            local attr_str = inner:sub(#tag_name + 1)
