                _name = tag_name,
                _attrs = attrs,
                _children = {},
                _type = "element"
            }
            table.insert(current._children, node)

            -- Also store by tag name for easy access
            if not current[tag_name] then
                current[tag_name] = node
            elseif type(current[tag_name]) == "table" and current[tag_name]._type then
                -- Convert to array
                current[tag_name] = { current[tag_name], node }
            elseif type(current[tag_name]) == "table" then
                table.insert(current[tag_name], node)
            end
        elseif tag_content:sub(1, 1) == "?" then
            -- Processing instruction, skip
        else
            -- Opening tag
            local tag_name = tag_content:match("^([%w_:%-%.]+)")
            if not tag_name then
                return nil, "Malformed XML: invalid opening tag"
            end
            local attr_str = tag_content:sub(#tag_name + 1)
            local attrs, err = self:parse_attributes(attr_str)
            if not attrs then
                return nil, err
            end

            local node = {
                _name = tag_name,
                _attrs = attrs,
                _children = {},
                _type = "element"
            }
            table.insert(current._children, node)

            -- Also store by tag name for easy access
            if not current[tag_name] then
