-- Helper: find a child element by local name (ignoring namespace prefix)
local function find_child(node, local_name)
    if not node or not node._children then
        return nil
    end
    for _, child in ipairs(node._children) do
        local child_local = child._name:match(":(.+)$") or child._name
        if child_local == local_name then
            return child
        end
    end
    return nil
end

-- Helper: find all children by local name
local function find_children(node, local_name)
    local results = {}
    if not node or not node._children then
        return results
    end
    for _, child in ipairs(node._children) do
        local child_local = child._name:match(":(.+)$") or child._name
        if child_local == local_name then
            table.insert(results, child)
        end
    end
    return results
end

-- Helper: get text content of a node
local function get_text(node)
    if not node then
        return nil
    end
    return node._text
end

-- Helper: get attribute value
local function get_attr(node, attr_name)
    if not node or not node._attrs then
        return nil
    end
    return node._attrs[attr_name]
end

-- Extract SOAP envelope data
local function extract_soap_data(root)
    local data = {
        soap_version = nil,
        action = nil,
        headers = {},
        body = {},
        method = nil,
        params = {}
    }

    -- Determine SOAP version from namespace
    local root_local = root._name:match(":(.+)$") or root._name
    if root_local ~= "Envelope" then
        return nil, "Root element is not a SOAP Envelope"
    end

    if root._attrs then
        for attr_name, attr_val in pairs(root._attrs) do
            if attr_val:match("schemas%.xmlsoap%.org/soap/envelope") then
                data.soap_version = "1.1"
            elseif attr_val:match("www%.w3%.org/2003/05/soap%-envelope") then
                data.soap_version = "1.2"
            end
        end
    end

    if not data.soap_version then
        data.soap_version = "unknown"
    end

    -- Extract Header
    local header = find_child(root, "Header")
    if header then
        for _, child in ipairs(header._children) do
            local child_local = child._name:match(":(.+)$") or child._name
            data.headers[child_local] = get_text(child) or child
        end
    end

    -- Extract Body
    local body = find_child(root, "Body")
    if not body then
        return nil, "SOAP Body not found"
    end

    -- The first child of Body is typically the operation/method
    if body._children and #body._children > 0 then
        local operation = body._children[1]
        local op_local = operation._name:match(":(.+)$") or operation._name
        data.method = op_local

        -- Extract parameters from the operation element
        if operation._children then
            for _, param in ipairs(operation._children) do
                local param_local = param._name:match(":(.+)$") or param._name
                local param_value = get_text(param)

                -- Handle nested elements
                if not param_value and param._children and #param._children > 0 then
                    local nested = {}
                    for _, nested_child in ipairs(param._children) do
                        local nc_local = nested_child._name:match(":(.+)$") or nested_child._name
                        nested[nc_local] = get_text(nested_child)
                    end
                    data.params[param_local] = nested
                else
                    data.params[param_local] = param_value
                end
            end
        end
    end

    return data
end

-- Build a SOAP fault response
local function build_soap_fault(fault_code, fault_string, detail)
    local detail_xml = ""
    if detail then
        detail_xml = "<detail><message>" .. detail:gsub("&", "&amp;"):gsub("<", "&lt;"):gsub(">", "&gt;") .. "</message></detail>"
    end

    return '<?xml version="1.0" encoding="UTF-8"?>' ..
        '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">' ..
        '<soap:Body>' ..
        '<soap:Fault>' ..
        '<faultcode>' .. fault_code .. '</faultcode>' ..
        '<faultstring>' .. fault_string:gsub("&", "&amp;"):gsub("<", "&lt;"):gsub(">", "&gt;") .. '</faultstring>' ..
        detail_xml ..
        '</soap:Fault>' ..
        '</soap:Body>' ..
        '</soap:Envelope>'
end

-- Build a SOAP success response
local function build_soap_response(method, result_data)
    local result_xml = ""
    if type(result_data) == "table" then
        for key, value in pairs(result_data) do
            local safe_value = tostring(value):gsub("&", "&amp;"):gsub("<", "&lt;"):gsub(">", "&gt;")
            result_xml = result_xml .. "<" .. key .. ">" .. safe_value .. "</" .. key .. ">"
        end
    elseif result_data then
        local safe_value = tostring(result_data):gsub("&", "&amp;"):gsub("<", "&lt;"):gsub(">", "&gt;")
        result_xml = "<result>" .. safe_value .. "</result>"
    end

    return '<?xml version="1.0" encoding="UTF-8"?>' ..
        '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">' ..
        '<soap:Body>' ..
        '<' .. method .. 'Response>' ..
        result_xml ..
        '</' .. method .. 'Response>' ..
        '</soap:Body>' ..
        '</soap:Envelope>'
end

