-- Main OpenResty handler
-- ============================================================

local function handle_request()
    -- Only accept POST for SOAP
    local method = ngx.req.get_method()
    if method ~= "POST" then
        ngx.status = 405
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.header["Allow"] = "POST"
        ngx.say(build_soap_fault("soap:Client", "Method Not Allowed", "Only POST method is accepted"))
        return ngx.exit(405)
    end

    -- Check Content-Type
    local content_type = ngx.req.get_headers()["Content-Type"] or ""
    if not content_type:match("text/xml") and not content_type:match("application/soap%+xml") and not content_type:match("application/xml") then
        ngx.status = 415
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("soap:Client", "Unsupported Media Type",
            "Expected Content-Type: text/xml or application/soap+xml"))
        return ngx.exit(415)
    end

    -- Read request body
    ngx.req.read_body()
    local body = ngx.req.get_body_data()

    if not body then
        -- Body might be in a temp file
        local body_file = ngx.req.get_body_file()
        if body_file then
            local fh, err = io.open(body_file, "r")
            if fh then
                body = fh:read("*a")
                fh:close()
            else
                ngx.status = 500
                ngx.header["Content-Type"] = "text/xml; charset=utf-8"
                ngx.say(build_soap_fault("soap:Server", "Internal Server Error",
                    "Failed to read request body: " .. tostring(err)))
                return ngx.exit(500)
            end
        end
    end

    if not body or body == "" then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("soap:Client", "Bad Request", "Empty request body"))
        return ngx.exit(400)
    end

    -- Enforce a maximum body size to prevent denial of service
    local max_body_size = 1048576 -- 1MB
    if #body > max_body_size then
        ngx.status = 413
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("soap:Client", "Request Entity Too Large",
            "Request body exceeds maximum allowed size"))
        return ngx.exit(413)
    end

    -- Parse XML with XXE protection
    local parser = XMLParser.new()
    local xml_doc, parse_err = parser:parse(body)

    if not xml_doc then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("soap:Client", "XML Parse Error", tostring(parse_err)))
        return ngx.exit(400)
    end

    -- Extract SOAP data
    local soap_data, soap_err = extract_soap_data(xml_doc)

    if not soap_data then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("soap:Client", "Invalid SOAP Message", tostring(soap_err)))
        return ngx.exit(400)
    end

    -- Log the parsed request for debugging
    ngx.log(ngx.INFO, "SOAP Request - Version: ", soap_data.soap_version,
        ", Method: ", tostring(soap_data.method),
        ", Params: ", cjson.encode(soap_data.params))

    -- ============================================================
    -- Route to appropriate handler based on SOAP method
    -- ============================================================

    local response_data
    local soap_method = soap_data.method

    if soap_method == "GetUser" then
        local user_id = soap_data.params["UserId"]
        if not user_id then
            ngx.status = 400
            ngx.header["Content-Type"] = "text/xml; charset=utf-8"
            ngx.say(build_soap_fault("soap:Client", "Missing Parameter", "UserId is required"))
            return ngx.exit(400)
        end
        response_data = {
            UserId = user_id,
            UserName = "JohnDoe",
            Email = "john@example.com",
            Status = "Active"
        }

    elseif soap_method == "CreateOrder" then
        local product_id = soap_data.params["ProductId"]
        local quantity = soap_data.params["Quantity"]
        local customer = soap_data.params["Customer"]

        if not product_id or not quantity then
            ngx.status = 400
            ngx.header["Content-Type"] = "text/xml; charset=utf-8"
            ngx.say(build_soap_fault("soap:Client", "Missing Parameters",
                "ProductId and Quantity are required"))
            return ngx.exit(400)
        end

        response_data = {
            OrderId = "ORD-" .. ngx.now() .. "-" .. math.random(1000, 9999),
            ProductId = product_id,
            Quantity = quantity,
            Status = "Created",
            Timestamp = ngx.http_time(ngx.time())
        }

    elseif soap_method == "HealthCheck" then
        response_data = {
            Status = "OK",
            Timestamp = ngx.http_time(ngx.time()),
            Version = "1.0.0"
        }

    else
        ngx.status = 500
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("soap:Server", "Unknown Operation",
            "The operation '" .. tostring(soap_method) .. "' is not supported"))
        return ngx.exit(500)
    end

    -- Send success response
    ngx.status = 200
    ngx.header["Content-Type"] = "text/xml; charset=utf-8"
    ngx.say(build_soap_response(soap_method, response_data))
    return ngx.exit(200)
end

-- Execute the handler
handle_request()